// Əsas tip təyinatı
let name: string = 'Ali';
let age: number = 25;
let isStudent: boolean = true;

console.log(`Ad: ${name}, Yaş: ${age}, Tələbə: ${isStudent}`);

// Massiv və funksiya tipləri
let numbers: number[] = [1, 2, 3];

function greet(person: string): string {
  return `Salam, ${person}!`;
}

console.log(greet('Vəli')); // Salam, Vəli!
console.log(numbers); // [1, 2, 3]

// İnterfeys nümunəsi
interface User {
  name: string;
  age: number;
  isActive?: boolean; // Opsional xassə
}

let user: User = {
  name: 'Ayşə',
  age: 30,
};

console.log(user); // { name: 'Ayşə', age: 30 }

// Sinif nümunəsi
class Person {
  private name: string;
  public age: number;

  constructor(name: string, age: number) {
    this.name = name;
    this.age = age;
  }

  public greet(): string {
    return `Salam, mən ${this.name}!`;
  }
}

let person = new Person('Fatma', 28);
console.log(person.greet()); // Salam, mən Fatma!

// Generik funksiya
function identity<T>(value: T): T {
  return value;
}

console.log(identity<string>('Hello')); // Hello
console.log(identity<number>(42)); // 42

// utils.ts faylı
export function add(a: number, b: number): number {
  return a + b;
}

// main.ts faylı
import { add } from './utils';

console.log(add(5, 3)); // 8

// Dekorator nümunəsi
function log(target: any, key: string) {
  console.log(`${key} metodu çağırıldı`);
}

class Example {
  @log
  sayHello() {
    return 'Hello!';
  }
}

let ex = new Example();
console.log(ex.sayHello()); // sayHello metodu çağırıldı
                            // Hello!

// React komponenti
import React from 'react';

interface Props {
  name: string;
}

const Greeting: React.FC<Props> = ({ name }) => {
  return <h1>Salam, {name}!</h1>;
};

export default Greeting;

// Təhlükəsiz tip yoxlaması
function calculateArea(length: number, width: number): number {
  return length * width;
}

// console.log(calculateArea('10', 5)); // Xəta: string number gözlənilir
console.log(calculateArea(10, 5)); // 50

// Səhvə yol açan nümunə
let data: any = 'Hello';
console.log(data.toUpperCase()); // İşləyir, lakin təhlükəsiz deyil

data = 42;
// console.log(data.toUpperCase()); // Runtime xətası

// Düzgün yol: Tip təyinatı
let text: string = 'Hello';
console.log(text.toUpperCase()); // HELLO

