// Basic type annotations
let name: string = 'Alice';
let age: number = 25;
let isStudent: boolean = true;

console.log(`Name: ${name}, Age: ${age}, Student: ${isStudent}`);

// Arrays and function types
let numbers: number[] = [1, 2, 3];

function greet(person: string): string {
  return `Hello, ${person}!`;
}

console.log(greet('Bob')); // Hello, Bob!
console.log(numbers); // [1, 2, 3]

// Interface example
interface User {
  name: string;
  age: number;
  isActive?: boolean; // Optional property
}

let user: User = {
  name: 'Eve',
  age: 30,
};

console.log(user); // { name: 'Eve', age: 30 }

// Class example
class Person {
  private name: string;
  public age: number;

  constructor(name: string, age: number) {
    this.name = name;
    this.age = age;
  }

  public greet(): string {
    return `Hello, I'm ${this.name}!`;
  }
}

let person = new Person('Grace', 28);
console.log(person.greet()); // Hello, I'm Grace!

// Generic function
function identity<T>(value: T): T {
  return value;
}

console.log(identity<string>('Hello')); // Hello
console.log(identity<number>(42)); // 42

// utils.ts file
export function add(a: number, b: number): number {
  return a + b;
}

// main.ts file
import { add } from './utils';

console.log(add(5, 3)); // 8

// Decorator example
function log(target: any, key: string) {
  console.log(`${key} method called`);
}

class Example {
  @log
  sayHello() {
    return 'Hello!';
  }
}

let ex = new Example();
console.log(ex.sayHello()); // sayHello method called
                            // Hello!

// React component
import React from 'react';

interface Props {
  name: string;
}

const Greeting: React.FC<Props> = ({ name }) => {
  return <h1>Hello, {name}!</h1>;
};

export default Greeting;

// Secure type checking
function calculateArea(length: number, width: number): number {
  return length * width;
}

// console.log(calculateArea('10', 5)); // Error: string not expected
console.log(calculateArea(10, 5)); // 50

// Error-prone example
let data: any = 'Hello';
console.log(data.toUpperCase()); // Works, but unsafe

data = 42;
// console.log(data.toUpperCase()); // Runtime error

// Correct approach: Type annotation
let text: string = 'Hello';
console.log(text.toUpperCase()); // HELLO

